#include<bits/stdc++.h>
using namespace std;
#define int long long

int gcd(int a, int b)
{
	if(b == 0) return a;
	return gcd(b, a % b);
}

int read() {
  int x = 0, w = 1;
  char ch = 0;
  while (ch < '0' || ch > '9') {  
    if (ch == '-') w = -1;        
    ch = getchar();               
  }
  while (ch >= '0' && ch <= '9') {  
    x = x * 10 + (ch - '0');  
    ch = getchar();  
  }
  return x * w;  
}

signed main(){
	int n;
	n = read();
	int d = 0;
	for(int i = 1; i <= n; i++)
	{
		int x = read();
		if(x % 2 == 1) 
		{
			cout << -1;
			return 0;
		}
		x /= 2;
		d = gcd(d, x);
	}
	cout << d;
}
